  1→//! Execute instrumented Rust code via subprocess compilation.
  2→//!
  3→//! Instruments the target function, generates a `main()` harness that links
  4→//! `shatter_rust_runtime`, compiles to a binary in a temp directory, runs it,
  5→//! and parses the JSON `ExecuteResult` from stdout.
  6→
  7→use std::io;
  8→use std::path::{Path, PathBuf};
  9→use std::process::Command;
 10→use std::time::{Duration, Instant};
 11→
 12→use serde_json::Value;
 13→
 14→use crate::instrument;
 15→
 16→/// Wrap instrumented source in `mod user_code { ... }` with all top-level items
 17→/// made `pub`, so the harness `main()` can call the target function without
 18→/// name collisions (e.g. duplicate `main()` from the original source).
 19→fn wrap_in_module(source: &str) -> Result<String, ExecuteError> {
 20→    use quote::ToTokens;
 21→
 22→    let mut file = syn::parse_file(source)
 23→        .map_err(|e| ExecuteError::InstrumentError(format!("parse error: {e}")))?;
 24→
 25→    for item in &mut file.items {
 26→        match item {
 27→            syn::Item::Fn(f) => f.vis = syn::Visibility::Public(syn::token::Pub::default()),
 28→            syn::Item::Struct(s) => s.vis = syn::Visibility::Public(syn::token::Pub::default()),
 29→            syn::Item::Enum(e) => e.vis = syn::Visibility::Public(syn::token::Pub::default()),
 30→            syn::Item::Type(t) => t.vis = syn::Visibility::Public(syn::token::Pub::default()),
 31→            syn::Item::Const(c) => c.vis = syn::Visibility::Public(syn::token::Pub::default()),
 32→            syn::Item::Static(s) => s.vis = syn::Visibility::Public(syn::token::Pub::default()),
 33→            syn::Item::Trait(t) => t.vis = syn::Visibility::Public(syn::token::Pub::default()),
 34→            syn::Item::Mod(m) => m.vis = syn::Visibility::Public(syn::token::Pub::default()),
 35→            _ => {}
 36→        }
 37→    }
 38→
 39→    let tokens = file.to_token_stream().to_string();
 40→    Ok(format!("#[allow(dead_code)]\nmod user_code {{\n{tokens}\n}}"))
 41→}
 42→
 43→/// Errors from the execute pipeline.
 44→#[derive(Debug)]
 45→pub enum ExecuteError {
 46→    /// Source file not found or unreadable.
 47→    FileError(String),
 48→    /// Instrumentation failed (parse error, etc.).
 49→    InstrumentError(String),
 50→    /// Failed to write temp project files.
 51→    IoError(io::Error),
 52→    /// `cargo build` failed with compiler output.
 53→    CompilationFailed(String),
 54→    /// Binary produced no parseable output.
 55→    OutputParseError(String),
 56→}
 57→
 58→impl std::fmt::Display for ExecuteError {
 59→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
 60→        match self {
 61→            Self::FileError(e) => write!(f, "file error: {e}"),
 62→            Self::InstrumentError(e) => write!(f, "instrumentation error: {e}"),
 63→            Self::IoError(e) => write!(f, "I/O error: {e}"),
 64→            Self::CompilationFailed(e) => write!(f, "compilation failed: {e}"),
 65→            Self::OutputParseError(e) => write!(f, "output parse error: {e}"),
 66→        }
 67→    }
 68→}
 69→
 70→impl From<io::Error> for ExecuteError {
 71→    fn from(e: io::Error) -> Self {
 72→        Self::IoError(e)
 73→    }
 74→}
 75→
 76→/// Result of executing an instrumented function. Uses `serde_json::Value`
 77→/// for fields to stay wire-compatible without duplicating runtime types.
 78→#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
 79→pub struct ExecuteResult {
 80→    pub return_value: Option<Value>,
 81→    pub thrown_error: Option<Value>,
 82→    #[serde(default)]
 83→    pub branch_path: Vec<Value>,
 84→    #[serde(default)]
 85→    pub lines_executed: Vec<u32>,
 86→    #[serde(default)]
 87→    pub calls_to_external: Vec<Value>,
 88→    #[serde(default)]
 89→    pub path_constraints: Vec<Value>,
 90→    #[serde(default)]
 91→    pub side_effects: Vec<Value>,
 92→    pub performance: Value,
 93→}
 94→
 95→const DEFAULT_BUILD_TIMEOUT_SECS: u64 = 30;
 96→
 97→/// Locate the shatter-rust-runtime crate by walking up from the shatter-rust binary.
 98→fn find_runtime_crate_path() -> Result<PathBuf, ExecuteError> {
 99→    // Try SHATTER_RUNTIME_PATH env var first (for testing and deployment).
100→    if let Ok(p) = std::env::var("SHATTER_RUNTIME_PATH") {
101→        let path = PathBuf::from(&p);
102→        if path.join("Cargo.toml").exists() {
103→            return Ok(path);
104→        }
105→    }
106→
107→    // Walk up from current exe to find shatter-rust-runtime as a sibling.
108→    if let Ok(exe) = std::env::current_exe() {
109→        let mut dir = exe.parent().map(Path::to_path_buf);
110→        for _ in 0..5 {
111→            if let Some(d) = &dir {
112→                let candidate = d.join("shatter-rust-runtime");
113→                if candidate.join("Cargo.toml").exists() {
114→                    return Ok(candidate);
115→                }
116→                dir = d.parent().map(Path::to_path_buf);
117→            }
118→        }
119→    }
120→
121→    Err(ExecuteError::FileError(
122→        "cannot locate shatter-rust-runtime crate; set SHATTER_RUNTIME_PATH".to_string(),
123→    ))
124→}
