323→/// Inner type conversion with a `converting` set to guard against recursive enums.
324→fn convert_type_inner(
325→    ty: &syn::Type,
326→    structs: &StructDefs,
327→    enums: &EnumDefs,
328→    generic_params: &HashSet<String>,
329→    converting: &mut HashSet<String>,
330→) -> TypeInfo {
331→    match ty {
332→        syn::Type::Path(type_path) => {
333→            convert_type_path(type_path, structs, enums, generic_params, converting)
334→        }
335→        syn::Type::Reference(type_ref) => {
336→            convert_reference(type_ref, structs, enums, generic_params, converting)
337→        }
338→        syn::Type::Tuple(type_tuple) => {
339→            convert_tuple(type_tuple, structs, enums, generic_params, converting)
340→        }
341→        syn::Type::Array(type_array) => TypeInfo::Array {
342→            element: Box::new(convert_type_inner(
343→                &type_array.elem,
344→                structs,
345→                enums,
346→                generic_params,
347→                converting,
348→            )),
349→        },
350→        syn::Type::Slice(type_slice) => TypeInfo::Array {
351→            element: Box::new(convert_type_inner(
352→                &type_slice.elem,
353→                structs,
354→                enums,
355→                generic_params,
356→                converting,
357→            )),
358→        },
359→        syn::Type::Paren(type_paren) => {
360→            convert_type_inner(&type_paren.elem, structs, enums, generic_params, converting)
361→        }
362→        syn::Type::BareFn(_) => TypeInfo::Complex {
363→            kind: ComplexKind::Closure,
364→            metadata: HashMap::new(),
365→            inner: None,
366→        },
367→        syn::Type::Never(_) => TypeInfo::Unknown,
368→        _ => TypeInfo::Unknown,
369→    }
