/// Returns true if a type string contains a trait object (`dyn Trait`).
///
/// Uses syn parsing for accuracy rather than substring matching, falling back
/// to a text heuristic if parsing fails.
fn contains_trait_object(ty_str: &str) -> bool {
    // Try parsing as a syn::Type for accurate detection.
    if let Ok(ty) = syn::parse_str::<syn::Type>(ty_str) {
        return has_trait_object_recursive(&ty);
    }
    // Fallback: text heuristic for when syn can't parse the fragment.
    ty_str.contains("dyn ")
}

fn has_trait_object_recursive(ty: &syn::Type) -> bool {
    match ty {
        syn::Type::TraitObject(_) => true,
        syn::Type::Reference(r) => has_trait_object_recursive(&r.elem),
        syn::Type::Paren(p) => has_trait_object_recursive(&p.elem),
        syn::Type::Slice(s) => has_trait_object_recursive(&s.elem),
        syn::Type::Array(a) => has_trait_object_recursive(&a.elem),
        syn::Type::Tuple(t) => t.elems.iter().any(has_trait_object_recursive),
        _ => false,
    }
}

